fn run_user_app(args: &[String], envs: &[String]) -> Option<i32> {
    let mut uspace = mm::new_user_aspace_empty()
        .and_then(|mut aspace| {
            map_for_umode(&mut aspace)?;
            Ok(aspace)
        })
        .expect("Failed to create user address space");

    let exec_path = args[0].clone();
    //let (dir, name) = exec_path.rsplit_once('/').unwrap_or(("", &exec_path));

    let name = with_fs(AT_FDCWD, |fs| {
        info!("exec_Path:{}", exec_path);
        let loc = fs.resolve(&exec_path)?;
        let name = loc.name().to_owned();
        fs.set_current_dir(loc.parent().unwrap())?;
        Ok(name)
    })
    .expect("Failed to resolve executable path");

    //axfs::api::set_current_dir(dir).expect("Failed to set current dir");

    let (entry_vaddr, ustack_top) = mm::load_user_app(&mut uspace, args, envs)
        .unwrap_or_else(|e| panic!("Failed to load user app: {}", e));
    let uctx = UspaceContext::new(entry_vaddr.into(), ustack_top, 2333); //用户态上下文

    let mut task = new_user_task(&name);
    task.ctx_mut().set_page_table_root(uspace.page_table_root());

    let process = sys_core::task::process::Process::new(
        exec_path,
        task.id().as_u64() as Tid,
        Arc::new(Mutex::new(uspace)),
        Arc::default(),
        Some(axsignal::Signo::SIGCHLD),
    );
    //todo:init_proc
    use posix_api::FD_TABLE;
    FD_TABLE
        .deref_from(&process.ns)
        .init_new(FD_TABLE.copy_inner());
    FS_CONTEXT
        .deref_from(&process.ns)
        .init_new(FS_CONTEXT.copy_inner());

    let thread = sys_core::task::Thread::new(task.id().as_u64() as Tid, Arc::new(process));
    add_to_tables(&thread);
    task.init_task_ext(TaskExt::new(uctx, thread)); //task 

    // let user_task = task::spawn_user_task(
    //     Arc::new(Mutex::new(uspace)),
    //     UspaceContext::new(entry_vaddr.into(), ustack_top, 2333),
    //     axconfig::plat::USER_HEAP_BASE as _,
    // );
    let task = axtask::spawn_task(task);
    task.join()
}

#[unsafe(no_mangle)]
fn main() {
    sys_core::vfs::mount_all().expect("Failed to mount vfs");
    let arch = format!("ARCH={}", option_env!("ARCH").unwrap_or("idk"));
    let is_shell = option_env!("R_SHELL").unwrap_or("no");
    if is_shell != "no" {
        let exit_code = run_user_app(
            &["/musl/busybox".to_string(), "sh".to_string()],
            &[
                "LD_LIBRARY_PATH=/glibc/lib/".to_string(),
                //"LD_DEBUG=all".to_string(),
                arch.to_string(),
            ],
        );
        info!(
            "User task {} exited with code: {:?}",
            "busybox sh", exit_code
        );
    } else {
        let testcases = option_env!("AX_TESTCASES_LIST")
            .unwrap_or_else(|| "Please specify the testcases list by making user_apps")
            .split(',')
            .filter(|&x| !x.is_empty());

        for testcase in testcases {
            let args = testcase
                .split_ascii_whitespace()
                .map(ToString::to_string)
                .collect::<Vec<_>>();

            let exit_code = run_user_app(
                &args,
                &[
                    "LD_LIBRARY_PATH=/glibc/lib/".to_string(),
                    //"LD_DEBUG=all".to_string(),
                    arch.to_string(),
                ],
            );
        }
        // let mut envs = Vec::new();

        // if args[0].contains("/glibc/") {
        //     envs.push("LD_LIBRARY_PATH=/glibc/lib/".to_string());
        // }
        // let exit_code = run_user_app(&args, &envs);

        let ltp_script = include_str!("ltp.sh");
        info!("run ltp script");
        let exit_code = run_user_app(
            &[
                "/musl/busybox".to_string(),
                "sh".to_string(),
                "-c".to_string(),
                ltp_script.to_string(),
            ],
            &[
                "LD_LIBRARY_PATH=/glibc/lib/".to_string(),
                //"LD_DEBUG=all".to_string(),
                arch.to_string(),
            ],
        );
    }
}

