pub struct Thread {
    tid: Tid,
    process: Arc<Process>,
    clear_child_tid: AtomicUsize,

    ///signal
    pub signal: ThreadSignalManager<RawMutex, WaitQueueWrapper>,
}

//星绽:kernel/src/process/task_set.rs

impl Thread {
    pub fn new(tid: Tid, process: Arc<Process>) -> Arc<Self> {
        let thread = Arc::new(Self {
            tid,
            clear_child_tid: AtomicUsize::new(0),
            signal: ThreadSignalManager::new(process.signal.clone()),
            process: process,
        });

        thread
    }
    pub fn tid(&self) -> Tid {
        self.tid
    }
    //引用，后续如果新建线程，则clone这个引用，clone后仍旧指向一个玩意，当所有线程被销毁，这玩意就无了
    pub fn process(&self) -> &Arc<Process> {
        &self.process
    }

    pub fn exit(&self, code: i32) -> bool {
        let mut tg = self.process.threads.lock();
        if !tg.has_exited_group {
            tg.exit_code = code;
        }
        tg.threads.retain(|t| t.tid != self.tid); //规模不大，还好？
        tg.threads.is_empty()
    }
    pub fn clear_child_tid(&self) -> usize {
        self.clear_child_tid.load(Ordering::Relaxed)
    }

    pub fn set_clear_child_tid(&self, clear_child_tid: usize) {
        self.clear_child_tid
            .store(clear_child_tid, Ordering::Relaxed);
    }
}
