static PROCESS_TABLE: RwLock<WeakMap<Tid, Weak<Process>>> = RwLock::new(WeakMap::new());
static PROCESS_GROUP_TABLE: RwLock<WeakMap<Tid, Weak<ProcessGroup>>> = RwLock::new(WeakMap::new());
use axerrno::{LinuxError, LinuxResult};

///添加此线程到线程表，进程表等
pub fn add_to_tables(thread: &Arc<Thread>) {
    let mut thread_table = THREAD_TABLE.write();
    thread_table.insert(thread.tid(), thread);

    let mut process_table = PROCESS_TABLE.write();
    let process = thread.process();
    if process_table.contains_key(&process.pid()) {
        return;
    }
    process_table.insert(process.pid(), process);
}
pub fn find_thread(tid: Tid) -> LinuxResult<Arc<Thread>> {
    THREAD_TABLE.read().get(&tid).ok_or(LinuxError::ESRCH)
}
pub fn find_process(tid: Tid) -> LinuxResult<Arc<Process>> {
    PROCESS_TABLE.read().get(&tid).ok_or(LinuxError::ESRCH)
}
//返回所有进程
pub fn get_all_processes() -> Vec<Arc<Process>> {
    PROCESS_TABLE.read().values().collect()
}

