//! Futex implementation optimized for SMP systems.

use alloc::{collections::btree_map::BTreeMap, sync::Arc};
use lazy_static::lazy_static;

use axconfig::SMP;
use axsync::Mutex;
use axtask::{TaskExtRef, WaitQueue, current};
use core::ops::Deref;

const SHARD_BITS: usize = SMP;
const SHARD_NUM: usize = 1 << SHARD_BITS;

/// A sharded futex table to reduce lock contention on SMP systems.
pub struct FutexTable {
    shards: [FutexShard; SHARD_NUM],
}

struct FutexShard {
    inner: Mutex<BTreeMap<usize, Arc<WaitQueue>>>,
}

impl FutexTable {
    /// Creates a new `FutexTable`.
    pub fn new() -> Self {
        Self {
            shards: [(); SHARD_NUM].map(|_| FutexShard {
                inner: Mutex::new(BTreeMap::new()),
            }),
        }
    }

    #[inline]
    fn select_shard(&self, addr: usize) -> &FutexShard {
        // Simple hash function to distribute addresses evenly
        let hash = (addr >> 2).wrapping_mul(0x9e3779b9);
        &self.shards[(hash as usize) & (SHARD_NUM - 1)]
    }

    /// Gets the wait queue associated with the given address.
    pub fn get(&self, addr: usize) -> Option<WaitQueueGuard> {
        let shard = self.select_shard(addr);
        let wq = shard.inner.lock().get(&addr).cloned()?;
        Some(WaitQueueGuard {
            key: addr,
            inner: wq,
        })
    }

    /// Gets the wait queue associated with the given address, or inserts a new one if it doesn't exist.
    pub fn get_or_insert(&self, addr: usize) -> WaitQueueGuard {
        let shard = self.select_shard(addr);
        let mut table = shard.inner.lock();
        let wq = table
            .entry(addr)
            .or_insert_with(|| Arc::new(WaitQueue::new()));
        WaitQueueGuard {
            key: addr,
            inner: wq.clone(),
        }
    }
}

#[doc(hidden)]
pub struct WaitQueueGuard {
    key: usize,
    inner: Arc<WaitQueue>,
}

impl Deref for WaitQueueGuard {
    type Target = Arc<WaitQueue>;

    fn deref(&self) -> &Self::Target {
        &self.inner
    }
}

lazy_static! {
    pub static ref FUTEX_TABLE: FutexTable = FutexTable::new();
}

impl Drop for WaitQueueGuard {
    fn drop(&mut self) {
        let shard = FUTEX_TABLE.select_shard(self.key);
        let mut table = shard.inner.lock();
        if Arc::strong_count(&self.inner) == 2 && self.inner.is_empty() {
            table.remove(&self.key);
        }
    }
}

