pub fn sys_kill(pid: i32, sig: u32) -> LinuxResult<isize> {
    let Some(sig) = make_siginfo(sig, SI_USER as _)? else {
        return Ok(0);
    };

    let _curr = current();
    let mut result = 0usize;

    match pid {
        1.. => {
            let proc = find_process(pid as Tid)?;
            send_signal_process(&proc, sig)?;
            result += 1;
        }
        0 => {
            //let pg = curr.task_ext().thread.process().group();
            //result += send_signal_process_group(&pg, sig);
        }
        -1 => {
            for proc in get_all_processes() {
                if proc.is_init() {
                    // init process
                    continue;
                }
                send_signal_process(&proc, sig.clone())?;
                result += 1;
            }
        }
        ..-1 => {
            //let pg = get_process_group((-pid) as Pid)?;
            //result += send_signal_process_group(&pg, sig);
        }
    }

    // Ok(result as isize)
    if result > 0 {
        Ok(0)
    } else {
        Err(LinuxError::ESRCH)
    }
}
pub fn sys_tkill(tid: Tid, signo: u32) -> LinuxResult<isize> {
    let Some(sig) = make_siginfo(signo, SI_TKILL as _)? else {
