pub fn sys_rt_sigtimedwait(
    set: UserConstPtr<SignalSet>,
    info: UserPtr<siginfo>,
    timeout: UserConstPtr<timespec>,
    sigsetsize: usize,
) -> LinuxResult<isize> {
    // check_sigset(sigsetsize)?;

    let set = unsafe { *set.get()? };
    let timeout: Option<Duration> = timeout
        .nullable(UserConstPtr::get)?
        .map(|ts| unsafe { TimeValue::new((*ts).tv_sec as _, (*ts).tv_nsec as _) });

    let Some(sig) = current()
        .task_ext()
        .thread
        .signal
        .wait_timeout(set, timeout)
    else {
        return Err(LinuxError::EAGAIN);
    };

    if let Some(info) = info.nullable(UserPtr::get)? {
        unsafe { *info = sig.0 };
    }

    Ok(0)
}

pub fn sys_rt_sigsuspend(
    tf: &mut TrapFrame,
    set: UserPtr<SignalSet>,
    sigsetsize: usize,
) -> LinuxResult<isize> {
    check_sigset(sigsetsize)?;

    let curr = current();
    let thr_data = &curr.task_ext().thread;
    let mut set = unsafe { *set.get()? };

    set.remove(Signo::SIGKILL);
    set.remove(Signo::SIGSTOP);

    let old_blocked = thr_data
        .signal
        .with_blocked_mut(|blocked| mem::replace(blocked, set));

    tf.set_retval(-LinuxError::EINTR.code() as usize);

    loop {
        if check_sig(tf, Some(old_blocked)) {
            break;
        }
        curr.task_ext().thread.process().signal.wait_signal();
    }

    Ok(0)
}
pub fn sys_sigaltstack(
    ss: UserConstPtr<SignalStack>,
    old_ss: UserPtr<SignalStack>,
) -> LinuxResult<isize> {
    current().task_ext().thread.signal.with_stack_mut(|stack| {
        if let Some(old_ss) = old_ss.nullable(UserPtr::get)? {
            unsafe { *old_ss = stack.clone() };
        }
        if let Some(ss) = ss.nullable(UserConstPtr::get)? {
            let ss = unsafe { ss.read() };
            if ss.size <= MINSIGSTKSZ as usize {
                return Err(LinuxError::ENOMEM);
            }
            let stack_ptr: UserConstPtr<u8> = ss.sp.into();
            let _ = stack_ptr.get_as_array(ss.size)?;

            *stack = ss.clone();
        }
        Ok(0)
    })
}

use axerrno::{LinuxError, LinuxResult};
use linux_raw_sys::general::{
    FUTEX_CMD_MASK, FUTEX_CMP_REQUEUE, FUTEX_REQUEUE, FUTEX_WAIT, FUTEX_WAKE, timespec,
};

use crate::ptr::{PtrWrapper, UserConstPtr, UserPtr};

use axhal::time::TimeValue;

use sys_core::futex::FUTEX_TABLE;

pub fn sys_futex(
    uaddr: UserConstPtr<u32>,
    futex_op: u32,
    value: u32,
    timeout: UserConstPtr<timespec>,
    uaddr2: UserPtr<u32>,
    value3: u32,
) -> LinuxResult<isize> {
    info!("futex {:?} {} {}", uaddr.address(), futex_op, value);

    let futex_table = &FUTEX_TABLE;

    let addr = uaddr.query_paddr()?.as_usize();

    let command = futex_op & (FUTEX_CMD_MASK as u32);
    match command {
        FUTEX_WAIT => {
            if *uaddr.get_as_ref()? != value {
                return Err(LinuxError::EAGAIN);
            }
            let wq = futex_table.get_or_insert(addr);

            if let Some(timeout) = timeout.nullable(|x| x.get_as_ref())? {
                wq.wait_timeout(TimeValue::new(timeout.tv_sec as _, timeout.tv_nsec as _));
            } else {
                wq.wait();
            }

            Ok(0)
        }
        FUTEX_WAKE => {
            let wq = futex_table.get(addr);
            let mut count = 0;
            if let Some(wq) = wq {
                for _ in 0..value {
                    if !wq.notify_one(false) {
                        break;
                    }
                    count += 1;
                }
            }
            axtask::yield_now();
            Ok(count)
        }
        FUTEX_REQUEUE | FUTEX_CMP_REQUEUE => {
            if command == FUTEX_CMP_REQUEUE && *uaddr.get_as_ref()? != value3 {
                return Err(LinuxError::EAGAIN);
            }
            let value2 = timeout.address().as_usize() as u32;

            let wq = futex_table.get(addr);
            let wq2 = futex_table.get_or_insert(uaddr2.address().as_usize());

            let mut count = 0;
            if let Some(wq) = wq {
                for _ in 0..value {
                    if !wq.notify_one(false) {
                        break;
                    }
                    count += 1;
                }
                if count == value as isize {
                    count += wq.requeue(value2 as usize, &wq2) as isize;
                }
            }
            Ok(count)
        }
        _ => Err(LinuxError::ENOSYS),
    }
}

