    pub semaphores: Vec<Semaphore>,
    pub nsems: u32,
    pub rmid: bool,
    pub perm: CTypeIpcPerm,
    pub otime: u64,
    pub ctime: u64,
    wait_queue: Arc<WaitQueue>,
    ncnt: u32,
    zcnt: u32,
}

impl SemSet {
    fn new(key: i32, nsems: u32, mode: u16) -> Self {
        let mut semaphores = Vec::with_capacity(nsems as usize);
        for _ in 0..nsems {
            semaphores.push(Semaphore {
                value: 0,
                pid: None,
            });
        }

        let ctime = axhal::time::current_ticks() as u64;

        SemSet {
            semid: {
                let mut semid_allocator = IPCID_ALLOCATOR.lock();
                semid_allocator.alloc()
            },
            key,
            semaphores,
            nsems,
            rmid: false,
            perm: CTypeIpcPerm {
                key: key as u32,
                uid: 0,
                gid: 0,
                cuid: 0,
                cgid: 0,
                mode,
                seq: 0,
            },
            otime: 0,
            ctime,
            wait_queue: Arc::new(WaitQueue::new()),
            ncnt: 0,
            zcnt: 0,
        }
    }

    fn get_sem(&self, sem_num: u16) -> LinuxResult<&Semaphore> {
        if (sem_num as u32) >= self.nsems {
            return Err(LinuxError::EINVAL);
        }
        Ok(&self.semaphores[sem_num as usize])
    }

    fn get_sem_mut(&mut self, sem_num: u16) -> LinuxResult<&mut Semaphore> {
        if (sem_num as u32) >= self.nsems {
            return Err(LinuxError::EINVAL);
        }
        Ok(&mut self.semaphores[sem_num as usize])
    }
}

/// Semaphore manager
struct SemManager {
    key_semid: BiBTreeMap<i32, i32>,                 // key <-> semid
    semid_semset: BTreeMap<i32, Arc<Mutex<SemSet>>>, // semid -> semset
    undo_map: BTreeMap<Pid, Vec<(i32, u16, i16)>>,   // For SEM_UNDO
}

impl SemManager {
    const fn new() -> Self {
        SemManager {
            key_semid: BiBTreeMap::new(),
            semid_semset: BTreeMap::new(),
            undo_map: BTreeMap::new(),
        }
    }

    fn get_semid_by_key(&self, key: i32) -> Option<i32> {
        self.key_semid.get_by_key(&key).cloned()
    }

    fn get_semset_by_semid(&self, semid: i32) -> Option<Arc<Mutex<SemSet>>> {
        self.semid_semset.get(&semid).cloned()
    }

    fn insert_key_semid(&mut self, key: i32, semid: i32) {
        self.key_semid.insert(key, semid);
    }

    fn insert_semid_semset(&mut self, semid: i32, semset: Arc<Mutex<SemSet>>) {
        self.semid_semset.insert(semid, semset);
    }

    fn remove_semid(&mut self, semid: i32) {
        if let Some(key) = self.key_semid.get_by_value(&semid).cloned() {
            self.key_semid.remove_by_key(&key);
        }
        self.semid_semset.remove(&semid);
    }

    fn add_undo(&mut self, pid: Pid, semid: i32, sem_num: u16, adj: i16) {
        self.undo_map
            .entry(pid)
            .or_default()
            .push((semid, sem_num, adj));
    }

    fn remove_undo(&mut self, pid: &Pid) -> Option<Vec<(i32, u16, i16)>> {
        self.undo_map.remove(pid)
    }
}

