use crate::fd::epoll::{EpollInstance, epoll_event};

/// Creates a new epoll instance.
///
/// It returns a file descriptor referring to the new epoll instance.
pub fn sys_epoll_create(size: c_int) -> LinuxResult<isize> {
    debug!("sys_epoll_create <= {}", size);

    if size < 0 {
        return Err(LinuxError::EINVAL);
    }
    let epoll_instance = EpollInstance::new(0);
    let ret = add_file_like(Arc::new(epoll_instance))?;
    Ok(ret as isize)
}

/// Control interface for an epoll file descriptor
pub fn sys_epoll_ctl(
    epfd: c_int,
    op: c_int,
    fd: c_int,
    event: UserPtr<epoll_event>,
) -> LinuxResult<isize> {
    debug!("sys_epoll_ctl <= epfd: {} op: {} fd: {}", epfd, op, fd);
    if epfd == fd {
        return Err(LinuxError::EINVAL);
    }
    let mut event = event.get_as_mut()?;
    let ret =
        unsafe { EpollInstance::from_fd(epfd)?.control(op as usize, fd as usize, &(*event))? };
    Ok(ret as _)
}

/// Waits for events on the epoll instance referred to by the file descriptor epfd.
pub fn sys_epoll_wait(
    epfd: c_int,
    events: UserPtr<epoll_event>,
    maxevents: c_int,
    timeout: c_int,
) -> LinuxResult<isize> {
    debug!(
        "sys_epoll_wait <= epfd: {}, maxevents: {}, timeout: {}",
        epfd, maxevents, timeout
    );
    let mut events = events.get_as_mut()?;
    if maxevents <= 0 {
        return Err(LinuxError::EINVAL);
    }
    let events = unsafe { core::slice::from_raw_parts_mut(events, maxevents as usize) };
    let deadline =
        (!timeout.is_negative()).then(|| wall_time() + Duration::from_millis(timeout as u64));
    let epoll_instance = EpollInstance::from_fd(epfd)?;
    loop {
        #[cfg(feature = "net")]
        axnet::poll_interfaces();
        let events_num = epoll_instance.poll_all(events)?;
        if events_num > 0 {
            return Ok(events_num as _);
        }

        if deadline.is_some_and(|ddl| wall_time() >= ddl) {
            debug!("    timeout!");
            return Ok(0);
        }
        crate::sys_sched_yield();
    }
}
