///https://elixir.bootlin.com/linux/v6.14/source/fs/select.c#L967
#[inline]
fn poll_impl(fds: &mut [pollfd], timeout: i64, block: bool) -> LinuxResult<isize> {
    let deadline = axhal::time::monotonic_time_nanos() + timeout as u64;
    loop {
        //NIC?
        #[cfg(feature = "net")]
        axnet::poll_interfaces();
        trace!("poll_impl_yield!!!");
        crate::sys_sched_yield();
        //管道没被关闭？
        let mut count = 0;
        for fd in fds.iter_mut() {
            let mut revents = 0; //c_short,到时候直接转换
            let filelike = get_file_like(fd.fd)?;
            match filelike.poll() {
                Ok(status) => {
                    debug!(
                        "poll_impl:fd:{} readable:{} writable:{}",
                        fd.fd, status.readable, status.writable
                    );
                    if (fd.events & POLLIN as i16) != 0 && status.readable {
                        revents |= POLLIN;
                    }
                    if (fd.events & POLLOUT as i16) != 0 && status.writable {
                        revents |= POLLOUT;
                    }
                }
                Err(e) => {
                    warn!("fd{} poll err{:?}", fd.fd, e);
                    revents = POLLERR;
                }
            }
            fd.revents = revents as _;
            if revents != 0 {
                count += 1;
            }
        }
        if count > 0 {
            return Ok(count);
        }
        if !block {
            //如果非阻塞，检查超时
            if axhal::time::monotonic_time_nanos() > deadline {
                return Ok(0);
            }
        }
    }
}

