pub struct TimeStat {
    utime_ns: usize, //用户态运行时间（纳秒）
    stime_ns: usize, //内核态运行时间（纳秒）
    user_timestamp: usize,
    kernel_timestamp: usize,
    timer_type: TimerType, //类型
    timer_interval_ns: usize,
    timer_remained_ns: usize,
}
//内核态时间增量:进入内核态，到退出内核态，所以说，进入时设置kernel_timestamp=now_time_ns，退出时减去，now_time_ns-kernel_timestamp计算增量
//随后设置用户态

impl Default for TimeStat {
    fn default() -> Self {
        Self::new()
    }
}

impl TimeStat {
    pub fn new() -> Self {
        Self {
            utime_ns: 0,
            stime_ns: 0,
            user_timestamp: 0,
            kernel_timestamp: 0,
            timer_type: TimerType::NONE,
            timer_interval_ns: 0,
            timer_remained_ns: 0,
        }
    }

    pub fn output(&self) -> (usize, usize) {
        (self.utime_ns, self.stime_ns)
    }

    pub fn reset(&mut self, current_timestamp: usize) {
        self.utime_ns = 0;
        self.stime_ns = 0;
        self.user_timestamp = 0;
        self.kernel_timestamp = current_timestamp;
        self.timer_type = TimerType::NONE
    }

    pub fn switch_into_kernel_mode(&mut self, current_timestamp: usize) {
        let now_time_ns = current_timestamp;
        let delta = now_time_ns - self.user_timestamp; //计算自上次记录以来的时间差，此时应该是用户态时间？
        self.utime_ns += delta; //用户态时间增加
        self.kernel_timestamp = now_time_ns; //更新内核态时间戳，切换到用户态前减去
        if self.timer_type != TimerType::NONE && self.timer_type != TimerType::REAL {
            //real现在使用axtask的定时器
            self.update_timer(delta);
        };
        if self.timer_type == TimerType::REAL {
            self.update_real_timer(delta);
        }
    }

    pub fn switch_into_user_mode(&mut self, current_timestamp: usize) {
        let now_time_ns = current_timestamp;
        let delta = now_time_ns - self.kernel_timestamp;
        self.stime_ns += delta;
        self.user_timestamp = now_time_ns;
        if self.timer_type == TimerType::PROF {
            self.update_timer(delta);
        }
        if self.timer_type == TimerType::REAL {
            self.update_real_timer(delta);
        }
    }

    pub fn switch_from_old_task(&mut self, current_timestamp: usize) {
        let now_time_ns = current_timestamp;
        let delta = now_time_ns - self.kernel_timestamp;
        self.stime_ns += delta;
        self.kernel_timestamp = now_time_ns;
        if self.timer_type == TimerType::PROF {
            self.update_timer(delta);
        }
        if self.timer_type == TimerType::REAL {
            self.update_real_timer(delta);
        }
    }
    //realtimer，所以不只是程序运行的时间片
    pub fn switch_to_new_task(&mut self, current_timestamp: usize) {
        let now_time_ns = current_timestamp;
        let delta = now_time_ns - self.kernel_timestamp;
        self.kernel_timestamp = now_time_ns;
        //REAL现在不需要了，对于prof，这里是切换到其他程序的，更新个蛋
        if self.timer_type == TimerType::REAL {
            self.update_real_timer(delta);
        }
    }

    pub fn set_timer(
        &mut self,
        timer_interval_ns: usize,
        timer_remained_ns: usize,
        timer_type: usize,
    ) -> bool {
        self.timer_type = timer_type.into();
        self.timer_interval_ns = timer_interval_ns;
        self.timer_remained_ns = timer_remained_ns;
        self.timer_type != TimerType::NONE
    }
    //todo:时间到，发送信号,这个不在realtimer中使用，同时，getitimer这个调用，对于realtimmer，可以考虑直接以原始值计算？
    pub fn update_timer(&mut self, delta: usize) {
        if self.timer_remained_ns == 0 {
            return;
        }
        if self.timer_remained_ns > delta {
            self.timer_remained_ns -= delta;
        } else {
            let curr = current();
            curr.task_ext()
                .thread
                .process()
                .signal
                .send_signal(SignalInfo::new(
                    Signo::from_repr(SIGALRM as u8).unwrap(),
                    SI_KERNEL as _,
                ));
            self.timer_remained_ns = 0;
        }
    }

    //unixbench的定时器基本上是只触发一次

    pub fn set_realtimer(
        &mut self,
        timer_interval_ns: usize,
        timer_remained_ns: usize,
        timer_type: usize,
    ) {
        self.timer_type = timer_type.into();
        self.timer_interval_ns = timer_interval_ns;
        self.timer_remained_ns = timer_remained_ns;
        //self.timer_type != TimerType::NONE;
        let curr = current().as_task_ref().clone(); //避免英年早逝？

        let current_time = axhal::time::wall_time();
        let remaining_duration = Duration::from_nanos(self.timer_remained_ns as u64);
        let deadline = current_time + remaining_duration;

        axtask::set_alarm_callback(deadline, move || {
            error!("time is up");
            //ax_println!("real timer");
            if curr.state() == TaskState::Exited {
                //必须检查进程状态，否则会再次尝试进入用户态,
                //ax_println!("exited");
                drop(curr);
                return;
            }
            //时间到
            curr.task_ext()
                .thread
                .process()
                .signal
                .send_signal(SignalInfo::new(
                    Signo::from_repr(SIGALRM as u8).unwrap(),
                    SI_KERNEL as _,
                ));
            let mut timestat = curr.task_ext().time.write();
            timestat.timer_remained_ns = 0;
            timestat.kernel_timestamp = wall_time_nanos() as _;
            error!("done?");
            //ax_println!("real timer done!");
            drop(timestat);
            drop(curr);
        });
    }
    pub fn update_real_timer(&mut self, delta: usize) {
        if self.timer_remained_ns == 0 {
            return;
        }
        if self.timer_remained_ns > delta {
            self.timer_remained_ns -= delta;
        } else {
            self.timer_remained_ns = 0;
        }
    }
    //对于getitimer在没到期之前，实时计时器的时间都不会被刷新，所以说，只要现场计算即可
}
pub fn get_timer_stat() -> (TimerType, usize, usize) {
    let curr_task = current();
    let time_stat = curr_task.task_ext().time.read();
    (
        time_stat.timer_type,
        time_stat.timer_interval_ns,
        time_stat.timer_remained_ns,
    )
}

