        const WEXITED =1<<2;
        /// 报告还未结束的用户进程的状态
        const WCONTINUED = 1 << 3;
        /// Wait for any child
        const WALL = 1 << 30;
        /// Wait for cloned process
        const WCLONE = 1 << 31;
        /// NOWAIT
        const WNOWAIT = 1 << 24;


    }

}
