bitflags::bitflags! {
    /// permissions for sys_mmap
    ///
    /// See <https://github.com/bminor/glibc/blob/master/bits/mman.h>
    #[derive(Debug)]
    struct MmapProt: i32 {
        ///No Access
        const PROT_NONE = 0;
        /// Page can be read.
        const PROT_READ = 1 << 0;
        /// Page can be written.
        const PROT_WRITE = 1 << 1;
        /// Page can be executed.
        const PROT_EXEC = 1 << 2;
        /// Extend change to start of growsdown vma (mprotect only).
        const PROT_GROWDOWN = 0x01000000;
        /// Extend change to start of growsup vma (mprotect only).
        const PROT_GROWSUP = 0x02000000;
    }
}

impl From<MmapProt> for MappingFlags {
    fn from(value: MmapProt) -> Self {
        let mut flags = MappingFlags::USER;
        if value.contains(MmapProt::PROT_READ) {
            flags |= MappingFlags::READ;
        }
        if value.contains(MmapProt::PROT_WRITE) {
            flags |= MappingFlags::WRITE;
        }
        if value.contains(MmapProt::PROT_EXEC) {
            flags |= MappingFlags::EXECUTE;
        }
        flags
    }
}

use linux_raw_sys::general::*;

bitflags::bitflags! {
    /// flags for sys_mmap
    ///
    /// See <https://github.com/bminor/glibc/blob/master/bits/mman.h>
    #[derive(Debug)]
    struct MmapFlags: u32 {
        /// Share changes
        const MAP_SHARED = 1 << 0;//1
        /// Changes private; copy pages on write.
        const MAP_PRIVATE = 1 << 1;//2
        ///Shared Validate
        const MAP_SHARED_VALIDATE= 0x3;
        /// Map address must be exactly as requested, no matter whether it is available.
        const MAP_FIXED = 1 << 4;
        /// Don't use a file.
        const MAP_ANONYMOUS = 1 << 5;
        /// Don't check for reservations.
        const MAP_NORESERVE = 1 << 14;
        /// Allocation is for a stack.
        const MAP_STACK = 0x20000;

        ///来自奇怪的地方
        const MAP_32BIT           = 0x40;
        const MAP_GROWSDOWN       = 0x100;
        const MAP_DENYWRITE       = 0x800;
        const MAP_EXECUTABLE      = 0x1000;
        const MAP_LOCKED          = 0x2000;
        const MAP_POPULATE        = 0x8000;
        const MAP_NONBLOCK        = 0x10000;
        const MAP_HUGETLB         = 0x40000;//2M
        const MAP_SYNC            = 0x80000;
        const MAP_FIXED_NOREPLACE = 0x100000;

        //1GB
        const HUGE_1GB=MAP_HUGETLB|MAP_HUGE_1GB;

    }
}
///void *mmap(void *addr, size_t length ,int " prot ", int " flags ,int fd, off_t offset);
pub(crate) fn sys_mmap(
    addr: usize,
    length: usize,
    prot: i32,
    flags: u32,
    fd: i32,
    offset: isize,
) -> LinuxResult<isize> {
    // Safety: addr is used for mapping, and we won't directly access it.

    let curr = current();
    let curr_ext = curr.task_ext();
    let mut aspace = curr_ext.thread.process().aspace.lock();
    let permission_flags = MmapProt::from_bits_truncate(prot);

    // 有文件支持
    // TODO: check illegal flags for mmap
    // An example is the flags contained none of MAP_PRIVATE, MAP_SHARED, or MAP_SHARED_VALIDATE.
    //先这样，不能跑再说
    let map_flags = MmapFlags::from_bits_truncate(flags);
    const REQUIRED_FLAGS: u32 = MmapFlags::MAP_PRIVATE.bits()
        | MmapFlags::MAP_SHARED.bits()
        | MmapFlags::MAP_SHARED_VALIDATE.bits();

    if (flags & REQUIRED_FLAGS) == 0 {
        return Err(LinuxError::EINVAL); // 非法标志
    }
    let page_size = if map_flags.contains(MmapFlags::HUGE_1GB) {
        PageSize::Size1G
    } else if map_flags.contains(MmapFlags::MAP_HUGETLB) {
        //2M
        PageSize::Size2M
    } else {
        PageSize::Size4K
    };
    error!(
        "sys_mmap: addr: {:x?}, length: {:x?}, prot: {:?}, flags: {:?}, fd: {:?}, offset: {:?}",
        addr, length, permission_flags, map_flags, fd, offset
    );

    let start = addr.align_down(page_size);
    let end = (addr + length).align_up(page_size);
    let aligned_length = end - start;

    let start_addr = if map_flags.contains(MmapFlags::MAP_FIXED) {
        if start == 0 {
            return Err(LinuxError::EINVAL);
        }
        let ret = VirtAddr::from(addr as usize);
        aspace.unmap(ret, aligned_length)?;
        ret
    } else {
        aspace
            .find_free_area(
                VirtAddr::from(addr as usize),
                aligned_length,
                VirtAddrRange::new(aspace.base(), aspace.end()),
                page_size,
            )
            .or(aspace.find_free_area(
                aspace.base(),
                aligned_length,
                VirtAddrRange::new(aspace.base(), aspace.end()),
                page_size,
            ))
            .ok_or(LinuxError::ENOMEM)?
    };

    let populate = if fd == -1 {
        false
    } else {
        !map_flags.contains(MmapFlags::MAP_ANONYMOUS)
    };

    if !map_flags.contains(MmapFlags::MAP_SHARED) {
        aspace.map_alloc(
            start_addr,
            aligned_length,
            permission_flags.into(), //这个玩意和pt
            populate,
            page_size,
        )?;
    } else {
        aspace.map_share(start_addr, aligned_length, permission_flags.into(), None)?;
    }

    if populate {
        let file = posix_api::get_file_like(fd)?;
        let file_size = file.stat()?.size as usize;
        let file = file
            .into_any()
            .downcast::<File>()
            .map_err(|_| LinuxError::EBADF)?;
        let mut file = file.inner();

        if offset < 0 || offset as usize >= file_size {
            return Err(LinuxError::EINVAL);
        }
        let offset = offset as usize;
        let length = core::cmp::min(length, file_size - offset);
        let mut buf = vec![0u8; length];
        file.read_at(&mut buf, offset as u64)?; //file...
        aspace.write(start_addr, page_size, &buf)?;
    }
    Ok(start_addr.as_usize() as _)
}

