/// Read data from the file indicated by `fd`.
///
/// Return the read size if success.
#[inline]
pub fn sys_read(fd: i32, buf: UserPtr<c_void>, count: usize) -> LinuxResult<isize> {
    let buf = buf.get_as_bytes(count)?;
    read_impl(fd, buf, count)
}

#[inline]
fn read_impl(fd: i32, buf: *const c_void, count: usize) -> LinuxResult<isize> {
    //let buf = buf.get_as_bytes(count)?;
    debug!("read_impl <= {} {:#x} {}", fd, buf as usize, count);

    if buf.is_null() {
        return Err(LinuxError::EFAULT);
    }
    let dst = unsafe { core::slice::from_raw_parts_mut(buf as *mut u8, count as usize) };
    #[cfg(feature = "fd")]
    {
        Ok(get_file_like(fd)?.read(dst)? as isize)
    }
    #[cfg(not(feature = "fd"))]
    match fd {
        0 => Ok(super::stdio::stdin().read(dst)? as ctypes::ssize_t),
        1 | 2 => Err(LinuxError::EPERM),
        _ => Err(LinuxError::EBADF),
    }
}
#[inline]
fn write_impl(fd: c_int, buf: *const c_void, count: usize) -> LinuxResult<isize> {
    if buf.is_null() {
        return Err(LinuxError::EFAULT);
    }
    let src = unsafe { core::slice::from_raw_parts(buf as *const u8, count) };
    #[cfg(feature = "fd")]
    {
        Ok(get_file_like(fd)?.write(src)? as isize)
    }
    #[cfg(not(feature = "fd"))]
    match fd {
        0 => Err(LinuxError::EPERM),
        1 | 2 => Ok(super::stdio::stdout().write(src)? as isize),
        _ => Err(LinuxError::EBADF),
    }
}

/// Write data to the file indicated by `fd`.
///
/// Return the written size if success.
#[inline]
pub fn sys_write(fd: i32, buf: UserConstPtr<c_void>, count: usize) -> LinuxResult<isize> {
    let buf = buf.get_as_bytes(count)?;
    debug!("sys_write <= {} {:#x} {}", fd, buf as usize, count);
    write_impl(fd, buf, count)
}

/// Write a vector.
#[inline]
pub fn sys_writev(
    fd: i32,
    iov: UserConstPtr<linux_raw_sys::general::iovec>,
    iocnt: i32,
) -> LinuxResult<isize> {
    debug!("sys_writev <= fd: {}", fd);
    let iov = iov.get_as_bytes(iocnt as _)?;
    if !(0..=1024).contains(&iocnt) {
        return Err(LinuxError::EINVAL);
    }

    let iovs = unsafe { core::slice::from_raw_parts(iov, iocnt as usize) };
    let mut ret = 0;
    for iov in iovs.iter() {
        if iov.iov_len == 0 {
            continue;
        }
        let result = write_impl(fd, iov.iov_base, iov.iov_len as usize)?;
        ret += result;

        if result < iov.iov_len as isize {
            break;
        }
    }

    Ok(ret)
}
/// Read a vector.
#[inline]
pub fn sys_readv(
    fd: i32,
    iov: UserConstPtr<linux_raw_sys::general::iovec>,
    iocnt: i32,
) -> LinuxResult<isize> {
    debug!("sys_readv <= fd: {}", fd);
    let iov = iov.get_as_bytes(iocnt as _)?;
    if !(0..=1024).contains(&iocnt) {
        return Err(LinuxError::EINVAL);
    }

    let iovs = unsafe { core::slice::from_raw_parts(iov, iocnt as usize) };

    let mut ret = 0;
    for iov in iovs.iter() {
        let result = read_impl(fd, iov.iov_base, iov.iov_len as usize)?;
        ret += result;

        if result < iov.iov_len as isize {
            break;
        }
    }

    Ok(ret)
}

