use sys_core::task::Tid;
pub fn do_exit(exit_code: i32, group_exit: bool) -> ! {
    let curr = current();
    let clear_child_tid = curr.task_ext().thread.clear_child_tid();

    let clear_child_tid = UserPtr::<Tid>::from(clear_child_tid);

    let futex_table = &FUTEX_TABLE;
    if let Ok(paddr) = clear_child_tid.query_paddr() {
        if let Ok(child_tid) = clear_child_tid.get_as(Layout::new::<Tid>()) {
            unsafe { *child_tid = 0 };
        }

        if let Some(futex) = futex_table.get(paddr.as_usize()) {
            //这个物理地址肯定是存在的
            futex.notify_one(false);
        }
        axtask::yield_now();
    }

    // if !clear_child_tid.is_null() {
    //     // TODO: check whether the address is valid
    //     unsafe {
    //         // TODO: Encapsulate all operations that access user-mode memory into a unified function
    //         *(clear_child_tid) = 0;
    //     }
    //     // TODO: wake up threads, which are blocked by futex, and waiting for the address pointed by clear_child_tid
    // }
    //

    let thread = &curr.task_ext().thread;
    let process = thread.process();
    if thread.exit(exit_code) {
        //如果线程所属进程(线程组)已经为空，清除当前进程
        // TODO: send exit signal to parent
        process.exit(exit_code);
        close_all_filelike();

        // TODO: clear namespace resources
        if let Some(parent) = process.parent() {
            if let Some(signo) = process.exit_signal {
                //向父进程发送退出信号
                debug!("exit_signal:{:?}", signo);
                parent
                    .signal
                    .send_signal(SignalInfo::new(signo, SI_KERNEL as _));
            }

            parent.child_exit_wq.notify_all(false) //唤醒
        }
    }
    if group_exit {
        process.group_exit();
        // TODO: send SIGKILL to other threads

        for thr in process.threads() {
            let _ = thr
                .signal
                .send_signal(SignalInfo::new(Signo::SIGKILL, SI_KERNEL as _));
        }
    }

    axtask::exit(exit_code)
}

