/// Get clock time since booting
pub fn sys_clock_gettime(clk: i32, tp: UserPtr<timespec>) -> LinuxResult<isize> {
    let ts = tp.get()?;
    if ts.is_null() {
        return Err(LinuxError::EFAULT);
    }
    let now = match clk as u32 {
        CLOCK_REALTIME => {
            debug!("realtime");
            axhal::time::wall_time().into()
        }
        CLOCK_MONOTONIC => axhal::time::monotonic_time().into(),
        _ => {
            warn!("Called sys_clock_gettime for unsupported clock {}", clk);
            return Err(LinuxError::EINVAL);
        }
    };
    unsafe { *ts = now };
    debug!("sys_clock_gettime: {}.{:09}s", now.tv_sec, now.tv_nsec);
    Ok(0)
}

/// Sleep some nanoseconds
///
/// TODO: should be woken by signals, and set errno
pub unsafe fn sys_nanosleep(req: *const timespec, rem: *mut timespec) -> c_int {
    syscall_body!(sys_nanosleep, {
        unsafe {
            if req.is_null() || (*req).tv_nsec < 0 || (*req).tv_nsec > 999999999 {
                return Err(LinuxError::EINVAL);
            }
        }

        let dur = unsafe {
            debug!("sys_nanosleep <= {}.{:09}s", (*req).tv_sec, (*req).tv_nsec);
            Duration::from(*req)
        };

        let now = axhal::time::monotonic_time();

        #[cfg(feature = "multitask")]
        axtask::sleep(dur); //这有个死锁？先这样
        #[cfg(not(feature = "multitask"))]
        axhal::time::busy_wait(dur);

        let after = axhal::time::monotonic_time();
        let actual = after - now;

        if let Some(diff) = dur.checked_sub(actual) {
            if !rem.is_null() {
                unsafe { (*rem) = diff.into() };
            }
            return Err(LinuxError::EINTR);
        }
        Ok(0)
    })
}

/// Get current system time and store in specific struct
pub fn sys_get_time_of_day(ts: UserPtr<timeval>) -> LinuxResult<isize> {
    let current_us = axhal::time::monotonic_time_nanos() as usize / 1000;
    let mut ts = ts.get()?;
    unsafe {
        *ts = timeval {
            tv_sec: (current_us / 1_000_000) as i64,
            tv_usec: (current_us % 1_000_000) as i64,
        }
    }
    Ok(0)
}

pub fn sys_getitimer(which: u32, value: UserPtr<itimerval>) -> LinuxResult<isize> {
    let value = value.nullable(|x| x.get_as_mut())?;
    if let Some(value) = value {
        match which {
            ITIMER_VIRTUAL | ITIMER_PROF | ITIMER_REAL => {
                let (_timer_type, interval_ns, remained_ns) = get_timer_stat();
                *value = itimerval {
                    it_interval: timeval {
                        tv_sec: interval_ns as i64 / 1_000_000_000,
                        tv_usec: interval_ns as i64 % 1_000_000_000,
                    },
                    it_value: timeval {
                        tv_sec: remained_ns as i64 / 1_000_000_000,
                        tv_usec: remained_ns as i64 % 1_000_000_000,
                    },
                };
                debug!("getitimer: {:?}", value);
                Ok(0)
            }

            _ => {
                warn!("timer type? {}", which);
                Err(LinuxError::EINVAL)
            }
        }
    } else {
        Err(LinuxError::EFAULT)
    }
}

pub fn sys_setitimer(
    which: u32,
    new_value: UserPtr<itimerval>,
    old_value: UserPtr<itimerval>,
) -> LinuxResult<isize> {
    //todo old_value

    if !old_value.is_null() {
        let _ = sys_getitimer(which, old_value)?;
    }

    //咋整real？
    let value = new_value.nullable(|x| x.get_as_mut())?;
    if let Some(new_value) = value {
        let curr = axtask::current();
        let mut tstat = curr.task_ext().time.write();
        let remained_ns = new_value.it_value.tv_sec * 1_000_000_000 + new_value.it_value.tv_usec;
        let interval_ns =
            new_value.it_interval.tv_sec * 1_000_000_000 + new_value.it_interval.tv_usec;

        if remained_ns == 0 {
            tstat.reset(axhal::time::monotonic_time_nanos() as _);
            return Ok(0);
        }
        match which {
            ITIMER_REAL => {
                tstat.set_realtimer(interval_ns as _, remained_ns as _, ITIMER_REAL as usize);
                Ok(0)
            }
            ITIMER_VIRTUAL | ITIMER_PROF => {
                tstat.set_timer(interval_ns as _, remained_ns as _, ITIMER_REAL as usize);
                Ok(0)
            }
            _ => {
                warn!("imer type? {}", which);
                Err(LinuxError::EINVAL)
            }
        }
    } else {
        Err(LinuxError::EFAULT)
    }
}
pub fn sys_times(tms: UserPtr<Tms>) -> LinuxResult<isize> {
    let (_, utime_us, _, stime_us) = time_stat_output();
    unsafe {
        *tms.get()? = Tms {
            tms_utime: utime_us,
            tms_stime: stime_us,
            tms_cutime: utime_us,
            tms_cstime: stime_us,
        }
    }
    Ok(nanos_to_ticks(monotonic_time_nanos()) as _)
}

pub fn sys_clock_getres(which: u32, ts: UserPtr<timeval>) -> LinuxResult<isize> {
    let ts = ts.nullable(|x| x.get())?;

    if let Some(mut ts) = ts {
        match which {
            CLOCK_MONOTONIC_COARSE => unsafe {
                *ts = timeval {
                    tv_sec: 0,
                    tv_usec: 4000000,
                };
            },
            _ => return Ok(0),
        };
    }

    Ok(0)
}

