#[register_trap_handler(POST_TRAP)] //这个玩意被用在trap之后做回调，和syscall不同，syscall只会选择第一个，这个则会遍历
fn post_trap_signal(tf: &mut TrapFrame, from_user: bool) {
    if !from_user {
        return; //非用户态的trap，退出
    }
    check_sig(tf, None);
}

pub fn check_sig(tf: &mut TrapFrame, restore_blocked: Option<SignalSet>) -> bool {
    let curr = current();

    //error!("handle taskid:{}", curr.id().as_u64());
    let Some((siginfo, act)) = curr
        .task_ext()
        .thread
        .signal
        .check_signals(tf, restore_blocked)
    else {
        return false;
    };

    let sig = siginfo.signo() as i32;
    match act {
        SignalOSAction::Terminate => {
            do_exit(sig as i32, true);
        }
        SignalOSAction::CoreDump => {
            // TODO: implement core dump
            error!("core dump");
            do_exit(128 + sig as i32, true);
        }
        SignalOSAction::Stop => {
            // TODO: implement stop

            do_exit(1, true);
        }
        SignalOSAction::Continue => {
            // TODO: implement continue
        }
        SignalOSAction::Handler => {
            // do nothing
        }
    }
    true
}
