}
pub fn find_thread_in_group(tgid: Tid, tid: Tid) -> LinuxResult<Arc<Thread>> {
    let thr = find_thread(tid)?;
    if thr.process().pid() != tgid {
        return Err(LinuxError::ESRCH);
    }
    Ok(thr)
}
pub fn make_siginfo(signo: u32, code: i32) -> LinuxResult<Option<SignalInfo>> {
